// LAYER 1+2: Extract & Validate (§4.1 PRE-validate)
// Zero-throw: returns Standard Contract error, never throws

const raw = $input.first().json;
const input = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

function ve(code, msg) {
  return [{ json: {
    success: false, error_code: code, error_message: msg, data: null,
    _meta: { source: 'DB_Get_Availability', timestamp: new Date().toISOString(), workflow_id: $workflow.id },
    _exit_early: true
  }}];
}

// === PROVIDER_ID VALIDATION ===
let provider_id;
if (input.provider_id === undefined || input.provider_id === null) {
  return ve('MISSING_FIELD', 'provider_id is required');
}
if (typeof input.provider_id === 'string') {
  const trimmed = input.provider_id.trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(trimmed)) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
  provider_id = parseInt(trimmed);
} else if (typeof input.provider_id === 'number') {
  provider_id = input.provider_id;
  if (!Number.isInteger(provider_id) || provider_id < 1) return ve('INVALID_TYPE', 'provider_id must be a positive integer');
} else {
  return ve('INVALID_TYPE', 'provider_id must be a number or numeric string');
}

// === SERVICE_ID VALIDATION ===
let service_id;
if (input.service_id === undefined || input.service_id === null) {
  return ve('MISSING_FIELD', 'service_id is required');
}
if (typeof input.service_id === 'string') {
  const trimmed = input.service_id.trim();
  const INT_RE = /^\d+$/;
  if (!INT_RE.test(trimmed)) return ve('INVALID_TYPE', 'service_id must be a positive integer');
  service_id = parseInt(trimmed);
} else if (typeof input.service_id === 'number') {
  service_id = input.service_id;
  if (!Number.isInteger(service_id) || service_id < 1) return ve('INVALID_TYPE', 'service_id must be a positive integer');
} else {
  return ve('INVALID_TYPE', 'service_id must be a number or numeric string');
}

// === DATE VALIDATION ===
let date;
if (input.date === undefined || input.date === null) {
  return ve('MISSING_FIELD', 'date is required (YYYY-MM-DD format)');
}
date = String(input.date).trim();

// Validate YYYY-MM-DD format
const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;
if (!DATE_RE.test(date)) return ve('INVALID_TYPE', 'date must be in YYYY-MM-DD format');

// Validate date exists (not Feb 30, etc.) and is future
const dateObj = new Date(date + 'T00:00:00Z');
if (isNaN(dateObj.getTime())) return ve('INVALID_DATE', 'date is not a valid calendar date');

// Check date components match (catches Feb 30 → Mar 02 normalization)
const [year, month, day] = date.split('-').map(Number);
if (dateObj.getUTCFullYear() !== year || (dateObj.getUTCMonth() + 1) !== month || dateObj.getUTCDate() !== day) {
  return ve('INVALID_DATE', 'date does not exist in the calendar');
}

return [{ json: {
  success: true,
  provider_id,
  service_id,
  date,
  _validated: true
}}];

// Gate: only pass valid items to Build Query
const input = $input.first().json;
if (input._exit_early) return [];
return [{ json: input }];

// Gate: only pass validation errors to skip query
const input = $input.first().json;
if (!input._exit_early) return [];
return [{ json: input }];

// Build query to get available slots
const { provider_id, service_id, date } = $input.first().json;

// Calculate start and end times for the date (UTC)
// Using date at midnight UTC to avoid timezone issues
const start_time = date + 'T00:00:00Z';
const end_time = date + 'T23:59:59Z';

// Generates 20-minute slots for the entire day (72 slots = 24h * 3 slots/hour)
const availability_query = `
  WITH time_slots AS (
    SELECT generate_series(
      '${start_time}'::timestamptz,
      '${end_time}'::timestamptz,
      '20 minutes'::interval
    ) AS slot_start
  )
  SELECT 
    ts.slot_start AT TIME ZONE 'UTC' AS slot_start,
    TO_CHAR(ts.slot_start AT TIME ZONE 'UTC', 'HH24:MI') AS display_time,
    CASE 
      WHEN b.id IS NULL THEN true 
      ELSE false 
    END AS is_available
  FROM time_slots ts
  LEFT JOIN bookings b ON 
    b.provider_id = ${provider_id}::int AND
    b.service_id = ${service_id}::int AND
    b.status != 'CANCELLED' AND
    b.start_time <= ts.slot_start + interval '20 minutes' AND
    b.start_time >= ts.slot_start - interval '20 minutes'
  ORDER BY ts.slot_start;
`;

return [{ json: {
  ...$input.first().json,
  availability_query,
  start_time,
  end_time
}}];

// Handle DB error during availability query
const e = $input.first().json;
const upstreamData = $('Build Availability Query').isExecuted ? $('Build Availability Query').first().json : {};
let error_code = 'DB_QUERY_ERROR';
let error_message = e.message || e.error?.message || 'Database query error';

if (error_message.includes('connection') || error_message.includes('ECONNREFUSED')) {
  error_code = 'DB_CONNECTION_ERROR';
  error_message = 'Database connection failed';
} else if (error_message.includes('timeout')) {
  error_code = 'DB_TIMEOUT';
  error_message = 'Database query timeout';
} else if (error_message.includes('relation') && error_message.includes('does not exist')) {
  error_code = 'TABLE_NOT_FOUND';
  error_message = 'Bookings table does not exist';
}

return [{ json: {
  ...upstreamData,
  success: false, error_code, error_message, data: null,
  _meta: { source: 'DB_Get_Availability', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Format availability response
const items = $input.all();
const upstreamData = $('Build Availability Query').isExecuted ? $('Build Availability Query').first().json : {};

// Filter available slots
const availableSlots = items
  .filter(item => item.json.is_available === true)
  .map(item => ({
    start_time: item.json.slot_start,
    display_time: item.json.display_time
  }));

return [{ json: {
  success: true,
  error_code: null,
  error_message: null,
  data: {
    provider_id: upstreamData.provider_id,
    service_id: upstreamData.service_id,
    date: upstreamData.date,
    slots: availableSlots,
    total_available: availableSlots.length
  },
  _meta: {
    source: 'DB_Get_Availability',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];

// UNIFIED OUTPUT — Standard Contract (§3.2)
const items = $input.all();
let finalItem = items.find(i => i.json.data !== undefined || i.json.error_code !== undefined);
if (!finalItem) finalItem = items.find(i => i.json._exit_early);
if (!finalItem) { 
  return [{ json: { success: false, error_code: 'PIPELINE_ERROR', error_message: 'No valid output found', data: null, _meta: { source: 'DB_Get_Availability', timestamp: new Date().toISOString(), workflow_id: $workflow.id } } }]; 
}
const input = finalItem.json;
return [{ json: {
  success: input.success === true,
  error_code: input.error_code || null,
  error_message: input.error_message || null,
  data: input.data || null,
  _meta: input._meta || {
    source: 'DB_Get_Availability',
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id
  }
}}];
